 1→const API_BASE = process.env.NEXT_PUBLIC_API_URL || "http://localhost:3000";
 2→
 3→export async function api<T = unknown>(
 4→  path: string,
 5→  options?: RequestInit,
 6→): Promise<T> {
 7→  const res = await fetch(`${API_BASE}${path}`, {
 8→    ...options,
 9→    headers: {
10→      "content-type": "application/json",
11→      ...options?.headers,
12→    },
13→    next: { revalidate: 10 },
14→  });
15→  return res.json();
16→}
17→
18→export function decodeToonTable(
19→  text: string,
20→): { fields: string[]; rows: Record<string, string>[] } | null {
21→  const lines = text.trim().split("\n");
22→  if (lines.length === 0) return null;
23→
24→  const firstLine = lines[0];
25→  if (!firstLine) return null;
26→  const headerMatch = firstLine.match(/^(\w+)\[(\d+)\]\{([^}]+)\}:$/);
27→  if (!headerMatch || !headerMatch[3]) return null;
28→
29→  const fields = headerMatch[3].split(",");
30→  const rows: Record<string, string>[] = [];
31→
32→  for (let i = 1; i < lines.length; i++) {
33→    const line = lines[i];
34→    if (!line) continue;
35→    const values = line.trim().split(",");
36→    const row: Record<string, string> = {};
37→    for (let j = 0; j < fields.length; j++) {
38→      const fieldName = fields[j];
39→      if (fieldName) row[fieldName] = values[j] || "";
40→    }
41→    rows.push(row);
42→  }
43→
44→  return { fields, rows };
45→}
