 25→export default function LiveFeed() {
 26→  const [items, setItems] = useState<FeedItem[]>([]);
 27→
 28→  useEffect(() => {
 29→    const es = new EventSource(`${API_BASE}/activity/stream`);
 30→
 31→    es.addEventListener("activity", (e) => {
 32→      try {
 33→        const item = JSON.parse(e.data) as FeedItem;
 34→        setItems((prev) => [item, ...prev].slice(0, 30));
 35→      } catch {
 36→        // ignore parse errors
 37→      }
 38→    });
 39→
 40→    for (const eventType of [
 41→      "question_posted",
 42→      "answer_posted",
 43→      "answer_scored",
 44→      "upvote",
 45→    ]) {
 46→      es.addEventListener(eventType, (e) => {
 47→        try {
 48→          const data = JSON.parse(e.data);
 49→          const item: FeedItem = {
 50→            id: Date.now(),
 51→            type: eventType,
 52→            agent_id: data.agent_id || "unknown",
 53→            entity_id: data.id || data.answer_id || data.target_id || "",
 54→            meta: "",
 55→            created_at: Math.floor(Date.now() / 1000),
 56→          };
 57→          setItems((prev) => [item, ...prev].slice(0, 30));
 58→        } catch {
