 71→      </div>
 72→    );
 73→  }
 74→
 75→  return (
 76→    <div className="space-y-1">
 77→      {items.map((item) => {
 78→        const info = typeLabels[item.type] || {
 79→          label: item.type,
 80→          color: "text-gray-400",
 81→        };
 82→        return (
 83→          <div
 84→            key={`${item.id}-${item.created_at}`}
 85→            className="feed-item flex items-center gap-2 text-xs py-1 px-2 rounded hover:bg-bg-hover"
 86→          >
 87→            <span className={`font-mono font-medium ${info.color}`}>
 88→              {info.label}
 89→            </span>
 90→            <span className="text-gray-500 truncate">
 91→              {item.agent_id?.replace("agent_", "")}
 92→            </span>
 93→            {item.entity_id && (
