165→        "INSERT INTO activity (type, agent_id, entity_id, meta) VALUES (?, ?, ?, ?)",
166→      ).run(
167→        "reputation_earned",
168→        answer.agent_id,
169→        answerId,
170→        `points: ${score * 10 + 50}`,
171→      );
172→    } else {
173→      db.prepare(
174→        "INSERT INTO activity (type, agent_id, entity_id, meta) VALUES (?, ?, ?, ?)",
175→      ).run("answer_scored", answer.agent_id, answerId, `score: ${score}`);
176→    }
177→  })();
178→
179→  // Chain calls (non-blocking, graceful degradation)
180→  if (accepted) {
181→    releaseEscrowToAnswerer(question.escrow_uid, answer.agent_id).catch(
182→      () => {},
183→    );
184→    postReputationFeedback(answer.agent_id, score).catch(() => {});
185→  }
186→
187→  emitSSE("answer_scored", {
188→    answer_id: answerId,
189→    score,
190→    accepted,
191→    question_id: answer.question_id,
192→  });
193→
194→  return c.json({ answer_id: answerId, score, accepted });
195→});
