  1→import { Hono } from "hono";
  2→import { nanoid } from "nanoid";
  3→import { z } from "zod";
  4→import { getDb } from "../db";
  5→import { emitSSE } from "../sse";
  6→import { decodeToon, encodeToon } from "../toon";
  7→
  8→const app = new Hono();
  9→
 10→const voteSchema = z.object({
 11→  target_type: z.enum(["question", "answer"]),
 12→  target_id: z.string().min(1),
 13→  value: z.literal(1),
 14→  voter_agent_id: z.string().min(1),
 15→});
 16→
 17→app.post("/", async (c) => {
 18→  const contentType = c.req.header("content-type") || "";
 19→  let data: Record<string, unknown>;
 20→
 21→  if (contentType.includes("toon")) {
 22→    const text = await c.req.text();
 23→    const parsed = decodeToon(text);
 24→    data = {
 25→      ...parsed,
 26→      value: Number(parsed.value),
 27→    };
 28→  } else {
 29→    data = (await c.req.json().catch(() => null)) as Record<string, unknown>;
 30→    if (!data) return c.json({ error: "Invalid JSON" }, 400);
 31→  }
 32→
 33→  const parsed = voteSchema.safeParse(data);
 34→  if (!parsed.success) {
 35→    return c.json({ error: parsed.error.flatten().fieldErrors }, 400);
 36→  }
 37→
 38→  const { target_type, target_id, voter_agent_id } = parsed.data;
 39→  const db = getDb();
 40→
 41→  // Verify voter exists
 42→  const voter = db
 43→    .prepare("SELECT id FROM agents WHERE id = ?")
 44→    .get(voter_agent_id);
 45→  if (!voter) return c.json({ error: "Voter agent not found" }, 404);
 46→
 47→  // Verify target exists and no self-vote
 48→  if (target_type === "question") {
 49→    const q = db
 50→      .prepare("SELECT agent_id FROM questions WHERE id = ?")
 51→      .get(target_id) as { agent_id: string } | null;
 52→    if (!q) return c.json({ error: "Question not found" }, 404);
 53→    if (q.agent_id === voter_agent_id)
 54→      return c.json({ error: "Cannot vote on your own question" }, 400);
 55→  } else {
 56→    const a = db
 57→      .prepare("SELECT agent_id FROM answers WHERE id = ?")
 58→      .get(target_id) as { agent_id: string } | null;
 59→    if (!a) return c.json({ error: "Answer not found" }, 404);
 60→    if (a.agent_id === voter_agent_id)
 61→      return c.json({ error: "Cannot vote on your own answer" }, 400);
 62→  }
 63→
 64→  const id = `vote_${nanoid(8)}`;
 65→
 66→  try {
 67→    db.transaction(() => {
 68→      db.prepare(
 69→        `INSERT INTO votes (id, voter_id, target_type, target_id, value)
 70→         VALUES (?, ?, ?, ?, ?)`,
 71→      ).run(id, voter_agent_id, target_type, target_id, 1);
 72→
 73→      // Increment upvotes counter on target
 74→      if (target_type === "question") {
 75→        db.prepare(
 76→          "UPDATE questions SET upvotes = upvotes + 1 WHERE id = ?",
 77→        ).run(target_id);
 78→      } else {
 79→        db.prepare("UPDATE answers SET upvotes = upvotes + 1 WHERE id = ?").run(
 80→          target_id,
 81→        );
 82→      }
 83→
 84→      db.prepare(
 85→        `INSERT INTO activity (type, agent_id, entity_id, meta)
 86→         VALUES (?, ?, ?, ?)`,
 87→      ).run("upvote", voter_agent_id, target_id, `target_type: ${target_type}`);
 88→    })();
 89→  } catch (e: any) {
 90→    if (e.message?.includes("UNIQUE constraint")) {
 91→      return c.json({ error: "Already voted on this target" }, 409);
 92→    }
 93→    throw e;
 94→  }
 95→
 96→  emitSSE("upvote", { voter: voter_agent_id, target_type, target_id });
 97→
 98→  const toonResponse = encodeToon({ id, target_type, target_id, value: 1 });
 99→  return c.text(toonResponse, 201, {
100→    "content-type": "application/toon",
101→  });
102→});
103→
104→app.delete("/:target_type/:target_id", (c) => {
105→  const db = getDb();
106→  const agentId = c.req.header("x-agent-id");
107→  if (!agentId) return c.json({ error: "Missing x-agent-id header" }, 401);
108→
109→  const target_type = c.req.param("target_type");
110→  const target_id = c.req.param("target_id");
111→
112→  const vote = db
113→    .prepare(
114→      "SELECT id FROM votes WHERE voter_id = ? AND target_type = ? AND target_id = ?",
115→    )
116→    .get(agentId, target_type, target_id);
117→
118→  if (!vote) return c.json({ error: "Vote not found" }, 404);
119→
120→  db.transaction(() => {
121→    db.prepare(
122→      "DELETE FROM votes WHERE voter_id = ? AND target_type = ? AND target_id = ?",
123→    ).run(agentId, target_type, target_id);
124→
125→    if (target_type === "question") {
126→      db.prepare(
127→        "UPDATE questions SET upvotes = MAX(0, upvotes - 1) WHERE id = ?",
128→      ).run(target_id);
129→    } else {
130→      db.prepare(
131→        "UPDATE answers SET upvotes = MAX(0, upvotes - 1) WHERE id = ?",
132→      ).run(target_id);
133→    }
134→  })();
135→
136→  return c.json({ deleted: true });
137→});
138→
139→export default app;
140→

  1→import { Hono } from "hono";
  2→import { getDb } from "../db";
  3→import { encodeToonTable } from "../toon";
  4→
  5→const app = new Hono();
  6→
  7→app.get("/", (c) => {
  8→  const db = getDb();
  9→  const tag = c.req.query("tag");
 10→  const limit = Math.min(Number(c.req.query("limit")) || 10, 100);
 11→  const format = c.req.query("format") || "toon";
 12→
 13→  let query: string;
 14→  const params: (string | number)[] = [];
 15→
 16→  if (tag) {
 17→    query = `
 18→      SELECT a.id, a.name,
 19→             COALESCE(SUM(r.score), 0) as total_score,
 20→             COALESCE(SUM(r.accept_count), 0) as accept_count,
 21→             COALESCE(SUM(r.answer_count), 0) as answer_count,
 22→             a.self_verified
 23→      FROM agents a
 24→      LEFT JOIN reputation r ON a.id = r.agent_id
 25→      LEFT JOIN skill_tags s ON r.tag_id = s.id
 26→      WHERE s.name = ?
 27→      GROUP BY a.id
 28→      HAVING total_score > 0
 29→      ORDER BY total_score DESC
 30→      LIMIT ?
 31→    `;
 32→    params.push(tag, limit);
 33→  } else {
 34→    query = `
 35→      SELECT a.id, a.name,
 36→             COALESCE(SUM(r.score), 0) as total_score,
 37→             COALESCE(SUM(r.accept_count), 0) as accept_count,
 38→             COALESCE(SUM(r.answer_count), 0) as answer_count,
 39→             a.self_verified
 40→      FROM agents a
 41→      LEFT JOIN reputation r ON a.id = r.agent_id
 42→      GROUP BY a.id
 43→      HAVING total_score > 0
 44→      ORDER BY total_score DESC
 45→      LIMIT ?
 46→    `;
 47→    params.push(limit);
 48→  }
 49→
 50→  const rows = db.prepare(query).all(...params) as any[];
 51→
 52→  // Pre-fetch all top tags in one query to avoid N+1
 53→  const agentIds = rows.map((r) => r.id);
 54→  const topTags: Record<string, string> = {};
 55→  if (agentIds.length > 0) {
 56→    const placeholders = agentIds.map(() => "?").join(",");
 57→    const tagRows = db
 58→      .prepare(
 59→        `SELECT r.agent_id, s.name
 60→         FROM reputation r
 61→         JOIN skill_tags s ON r.tag_id = s.id
 62→         WHERE r.agent_id IN (${placeholders})
 63→         AND r.score = (
 64→           SELECT MAX(r2.score) FROM reputation r2 WHERE r2.agent_id = r.agent_id
 65→         )`,
 66→      )
 67→      .all(...agentIds) as { agent_id: string; name: string }[];
 68→    for (const row of tagRows) {
 69→      topTags[row.agent_id] = row.name;
 70→    }
 71→  }
 72→
 73→  const enriched = rows.map((row, i) => {
 74→    const rate =
 75→      row.answer_count > 0
 76→        ? ((row.accept_count / row.answer_count) * 100).toFixed(1)
 77→        : "0.0";
 78→
 79→    return {
 80→      rank: i + 1,
 81→      name: row.name,
 82→      score: row.total_score,
 83→      accept_count: row.accept_count,
 84→      acceptance_rate: `${rate}%`,
 85→      top_tag: topTags[row.id] || "none",
 86→      verified: row.self_verified ? "true" : "false",
 87→    };
 88→  });
 89→
 90→  if (format === "json") {
 91→    return c.json(enriched);
 92→  }
 93→
 94→  // TOON format
 95→  const toon = encodeToonTable(
 96→    "agents",
 97→    [
 98→      "rank",
 99→      "name",
100→      "score",
101→      "accept_count",
102→      "acceptance_rate",
103→      "top_tag",
104→      "verified",
105→    ],
106→    enriched.map((r) => [
107→      r.rank,
108→      r.name,
109→      r.score,
110→      r.accept_count,
111→      r.acceptance_rate,
112→      r.top_tag,
113→      r.verified,
114→    ]),
115→  );
116→
117→  return c.text(toon, 200, { "content-type": "application/toon" });
118→});
119→
120→export default app;
