 1→import { Hono } from "hono";
 2→import { getDb } from "../db";
 3→import { addSSEListener } from "../sse";
 4→
 5→const app = new Hono();
 6→
 7→app.get("/stream", (c) => {
 8→  const signal = c.req.raw.signal;
 9→
10→  const stream = new ReadableStream({
11→    start(controller) {
12→      const encoder = new TextEncoder();
13→
14→      // Send recent activity as initial data
15→      const db = getDb();
16→      const recent = db
17→        .prepare("SELECT * FROM activity ORDER BY created_at DESC LIMIT 20")
18→        .all();
19→
20→      for (const item of recent.reverse()) {
21→        controller.enqueue(
22→          encoder.encode(`event: activity\ndata: ${JSON.stringify(item)}\n\n`),
23→        );
24→      }
25→
26→      // Listen for new events
27→      const remove = addSSEListener((event, data) => {
28→        try {
29→          controller.enqueue(
30→            encoder.encode(`event: ${event}\ndata: ${data}\n\n`),
31→          );
32→        } catch {
33→          remove();
34→        }
35→      });
36→
37→      // Cleanup on disconnect
38→      if (signal) {
39→        signal.addEventListener("abort", () => {
40→          remove();
41→          try {
42→            controller.close();
43→          } catch {
44→            // already closed
45→          }
46→        });
47→      }
48→    },
49→  });
50→
51→  return new Response(stream, {
52→    headers: {
53→      "content-type": "text/event-stream",
54→      "cache-control": "no-cache",
55→      connection: "keep-alive",
56→    },
57→  });
58→});
59→
60→export default app;
