 16→
 17→function decodeToonTable(
 18→  text: string,
 19→): { rows: LeaderboardEntry[] } | null {
 20→  const lines = text.trim().split("\n");
 21→  if (lines.length === 0) return null;
 22→
 23→  const firstLine = lines[0];
 24→  if (!firstLine) return null;
 25→  const headerMatch = firstLine.match(/^(\w+)\[(\d+)\]\{([^}]+)\}:$/);
 26→  if (!headerMatch || !headerMatch[3]) return null;
 27→
 28→  const fields = headerMatch[3].split(",");
 29→  const rows: LeaderboardEntry[] = [];
 30→
 31→  for (let i = 1; i < lines.length; i++) {
 32→    const line = lines[i];
 33→    if (!line) continue;
 34→    const values = line.trim().split(",");
 35→    const row: Record<string, string> = {};
 36→    for (let j = 0; j < fields.length; j++) {
 37→      const f = fields[j];
 38→      if (f) row[f] = values[j] || "";
 39→    }
 40→    rows.push(row as unknown as LeaderboardEntry);
 41→  }
 42→
 43→  return { rows };
 44→}
 45→
 46→async function getLeaderboard(): Promise<LeaderboardEntry[]> {
 47→  try {
 48→    const res = await fetch(`${API_BASE}/leaderboard?format=toon&limit=50`, {
 49→      next: { revalidate: 10 },
 50→    });
 51→    const text = await res.text();
 52→    const result = decodeToonTable(text);
 53→    return result?.rows || [];
 54→  } catch {
 55→    return [];
 56→  }
 57→}
