 1→// TOON format encoder/decoder — lightweight tabular format for agent communication
 2→// TOON is simpler than JSON: key-value pairs or tabular arrays
 3→
 4→export function encodeToon(data: Record<string, unknown>): string {
 5→  return Object.entries(data)
 6→    .map(([k, v]) => `${k}: ${v}`)
 7→    .join("\n");
 8→}
 9→
10→export function encodeToonTable(
11→  name: string,
12→  fields: string[],
13→  rows: unknown[][],
14→): string {
15→  const header = `${name}[${rows.length}]{${fields.join(",")}}:`;
16→  const body = rows.map((row) => `  ${row.join(",")}`).join("\n");
17→  return `${header}\n${body}`;
18→}
19→
20→export function decodeToon(text: string): Record<string, string> {
21→  const result: Record<string, string> = {};
22→  for (const line of text.split("\n")) {
23→    const trimmed = line.trim();
24→    if (!trimmed) continue;
25→    const colonIdx = trimmed.indexOf(":");
26→    if (colonIdx === -1) continue;
27→    const key = trimmed.slice(0, colonIdx).trim();
28→    const value = trimmed.slice(colonIdx + 1).trim();
29→    result[key] = value;
30→  }
31→  return result;
32→}
33→
34→export function decodeToonTable(
35→  text: string,
36→): { name: string; fields: string[]; rows: Record<string, string>[] } | null {
37→  const lines = text.trim().split("\n");
38→  if (lines.length === 0) return null;
39→
40→  const firstLine = lines[0];
41→  if (!firstLine) return null;
42→  const headerMatch = firstLine.match(/^(\w+)\[(\d+)\]\{([^}]+)\}:$/);
43→  if (!headerMatch) return null;
44→
45→  const name = headerMatch[1] as string;
46→  const fields = (headerMatch[3] as string).split(",");
47→  const rows: Record<string, string>[] = [];
48→
49→  for (let i = 1; i < lines.length; i++) {
50→    const line = lines[i];
51→    if (!line) continue;
52→    const values = line.trim().split(",");
53→    const row: Record<string, string> = {};
54→    for (let j = 0; j < fields.length; j++) {
55→      const fieldName = fields[j] as string;
56→      row[fieldName] = values[j] || "";
57→    }
58→    rows.push(row);
59→  }
60→
61→  return { name, fields, rows };
62→}
63→

 1→type SSEListener = (event: string, data: string) => void;
 2→
 3→const listeners = new Set<SSEListener>();
 4→
 5→export function addSSEListener(listener: SSEListener): () => void {
 6→  listeners.add(listener);
 7→  return () => listeners.delete(listener);
 8→}
 9→
10→export function emitSSE(event: string, data: unknown): void {
11→  const json = JSON.stringify(data);
12→  for (const listener of listeners) {
13→    try {
14→      listener(event, json);
15→    } catch {
16→      // listener disconnected, will be cleaned up
17→    }
18→  }
19→}
